-- ── constants ───────────────────────────────────────────────────────────────────────────────
local PLUGIN_W = 420   -- forces window content width via imgui.dummy()

-- Colour map: rarity name -> {r, g, b}
local RARITY_COL = {
  Common    = {0.75, 0.75, 0.75},
  Uncommon  = {0.12, 0.85, 0.12},
  Rare      = {0.15, 0.55, 1.00},
  Epic      = {0.70, 0.25, 0.95},
  Legendary = {1.00, 0.70, 0.10},
}

-- ── state ───────────────────────────────────────────────────────────────────────────────────
local state = {
  search      = "",        -- current search query (persisted)
  filter      = "all",     -- "all" | "item" | "mob" (persisted)
  results     = {},        -- [{tp, id, nm, nm_lo}] -- current result list
  sel_type    = nil,       -- "item" or "unit" -- what is selected
  sel_id      = nil,       -- id string of selected entry
  detail_pois = {},        -- farever.pois() entries matching selected item's nodes
  nav_locked  = false,     -- true = nav arrow points at nav_poi indefinitely
  nav_poi     = nil,       -- poi object currently shown in the nav panel
  pois_cache  = nil,       -- farever.pois() result cached for 4 s
  pois_t      = 0,         -- farever.now() at last pois_cache fill
}

-- ── search index ───────────────────────────────────────────────────────────────────────
-- Flat list built once in on_init; each entry: {tp, id, nm, nm_lo}
-- tp="item" or "unit", nm_lo = name:lower() for fast case-insensitive match.
local search_idx = {}

local function build_index()
  search_idx = {}
  for id, it in pairs(DB.items) do
    -- skip internal IDs that have no display name
    if it.n and it.n ~= "" and it.n ~= id then
      search_idx[#search_idx+1] = {tp="item", id=id, nm=it.n, nm_lo=it.n:lower()}
    end
  end
  for id, u in pairs(DB.units) do
    if u.n and u.n ~= "" then
      search_idx[#search_idx+1] = {tp="unit", id=id, nm=u.n, nm_lo=u.n:lower()}
    end
  end
  -- Pre-sort alphabetically so prefix hits already appear in order
  table.sort(search_idx, function(a,b) return a.nm_lo < b.nm_lo end)
end

local function do_search(q)
  if q == "" then state.results = {}; return end
  local lo = q:lower()
  -- Two-pass: prefix matches ranked above contains matches
  local prefix, contains = {}, {}
  for _, e in ipairs(search_idx) do
    if e.nm_lo:sub(1, #lo) == lo then
      prefix[#prefix+1] = e
    elseif e.nm_lo:find(lo, 1, true) then
      contains[#contains+1] = e
    end
  end
  local res = {}
  for _, e in ipairs(prefix)   do res[#res+1] = e end
  for _, e in ipairs(contains) do res[#res+1] = e end
  -- Apply type filter (All / Items / Mobs)
  if state.filter ~= "all" then
    local ft = state.filter
    local filtered = {}
    for _, e in ipairs(res) do
      if (ft == "item" and e.tp == "item") or
         (ft == "mob"  and e.tp == "unit") then
        filtered[#filtered+1] = e
      end
    end
    res = filtered
  end
  -- Cap at 25 to keep the list readable
  if #res > 25 then
    local cut = {}; for i=1,25 do cut[i] = res[i] end; res = cut
  end
  state.results = res
end

-- ── poi helpers ──────────────────────────────────────────────────────────────────────────

-- Lazy-refreshed every 4 s to avoid hammering farever.pois() every frame.
local function get_pois()
  local now = farever.now()
  if not state.pois_cache or now - state.pois_t > 4 then
    state.pois_cache = farever.pois()
    state.pois_t     = now
  end
  return state.pois_cache
end

-- Return all farever.pois() ore/plant entries whose name prefix matches any
-- loot-table source of item_id.  e.g. CopperOre -> Ore_Copper -> "CopperOre"
-- prefix -> all CopperOre_Small / CopperOre_Large POIs.
local function find_pois_for_item(item_id)
  local src = DB.sources[item_id]
  if not src or not src.lt then return {} end
  local prefixes = {}
  for _, lt_src in ipairs(src.lt) do
    local pfx = DB.lt_to_poi[lt_src.id]
    if pfx then prefixes[pfx] = true end
  end
  if not next(prefixes) then return {} end
  local matching = {}
  for _, poi in ipairs(get_pois()) do
    if (poi.kind == "ore" or poi.kind == "plant") and poi.name then
      for pfx, _ in pairs(prefixes) do
        if poi.name:sub(1, #pfx) == pfx then
          matching[#matching+1] = poi; break
        end
      end
    end
  end
  return matching
end

local function poi_dist(poi)
  local dx = poi.x - farever.player.x()
  local dy = poi.y - farever.player.y()
  return math.sqrt(dx*dx + dy*dy)
end

local function sort_pois_by_dist(pois)
  table.sort(pois, function(a,b) return poi_dist(a) < poi_dist(b) end)
end

-- ── selection ────────────────────────────────────────────────────────────────────────────

local function select_entry(tp, id)
  state.sel_type    = tp
  state.sel_id      = id
  state.nav_locked  = false
  state.nav_poi     = nil
  state.detail_pois = {}
  if tp == "item" then
    local pois = find_pois_for_item(id)
    sort_pois_by_dist(pois)
    state.detail_pois = pois
    -- Auto-point nav arrow at the nearest node (can be locked by user later)
    if #pois > 0 then state.nav_poi = pois[1] end
  end
end

-- ── nav arrow ────────────────────────────────────────────────────────────────────────────
-- Same heading-relative compass math as POI Finder v2 (draw_triangle + draw_line).
-- dir_x / dir_y are unit-vector screen direction (ImGui +Y = down).

local function draw_nav_arrow(cx, cy, r, dir_x, dir_y, cr, cg, cb)
  local tip_x  = cx + dir_x * r
  local tip_y  = cy + dir_y * r
  local left_x = cx + (-dir_y * r * 0.45) - dir_x * r * 0.55
  local left_y = cy + ( dir_x * r * 0.45) - dir_y * r * 0.55
  local rgt_x  = cx + ( dir_y * r * 0.45) - dir_x * r * 0.55
  local rgt_y  = cy + (-dir_x * r * 0.45) - dir_y * r * 0.55
  local tail_x = cx - dir_x * r * 0.30
  local tail_y = cy - dir_y * r * 0.30
  imgui.draw_triangle_filled(tip_x,tip_y, left_x,left_y, rgt_x,rgt_y, cr,cg,cb,1)
  imgui.draw_line(tail_x,tail_y, cx,cy, cr,cg,cb,2)
end

local function render_nav_panel(poi)
  if not poi then return end
  local px, py, pz = farever.player.x(), farever.player.y(), farever.player.z()
  local heading    = farever.player.rot_z()
  -- World delta -> player-local frame -> screen direction
  local dx  = poi.x - px;  local dy = poi.y - py;  local dz = poi.z - pz
  local cosh, sinh  = math.cos(heading), math.sin(heading)
  local fwd  =  dx*cosh + dy*sinh
  local rgt  = -dx*sinh + dy*cosh
  local d_h  = math.sqrt(fwd*fwd + rgt*rgt)
  local theta_h = math.atan(rgt, fwd)      -- 0 = straight ahead
  local theta_v = math.atan(dz, math.max(d_h, 1.0))
  local dir_x =  math.sin(theta_h)         -- ImGui +Y = down, so forward = -Y
  local dir_y = -math.cos(theta_h)
  -- Distance-based colour: green < 30 m, yellow < 100 m, blue otherwise
  local dist_xy = math.floor(d_h)
  local dz_txt  = dz >= 0 and ("+" .. math.floor(dz)) or tostring(math.floor(dz))
  local cr, cg, cb
  if     dist_xy < 30  then cr,cg,cb = 0.2,1.0,0.3
  elseif dist_xy < 100 then cr,cg,cb = 1.0,0.85,0.1
  else                       cr,cg,cb = 0.3,0.7,1.0 end
  -- Panel background + border
  local cx_s, cy_s = imgui.cursor_pos()
  local panel_h    = 80
  imgui.draw_rect_filled(cx_s, cy_s, cx_s+PLUGIN_W, cy_s+panel_h, 0.05,0.05,0.1,0.85)
  imgui.draw_rect(cx_s, cy_s, cx_s+PLUGIN_W, cy_s+panel_h, cr,cg,cb,0.5,1)
  -- Arrow circle
  local ar = 28
  local acx, acy = cx_s + ar + 8, cy_s + panel_h/2
  imgui.draw_circle_filled(acx, acy, ar, 0.1,0.1,0.2,0.9)
  imgui.draw_circle(acx, acy, ar, cr,cg,cb,0.7,1.5)
  -- Small ring to show vertical elevation offset
  local tilt_scale = math.min(math.abs(theta_v) / (math.pi/4), 1.0)
  if tilt_scale > 0.05 then
    local tilt_dir = theta_v > 0 and -1 or 1
    imgui.draw_circle(acx, acy + tilt_dir*ar*0.25, ar*0.35, cr,cg,cb, tilt_scale*0.5,1)
  end
  draw_nav_arrow(acx, acy, ar*0.75, dir_x, dir_y, cr, cg, cb)
  -- Text: node name (without _Small/_Large), distance, coordinates
  local tx, ty = acx + ar + 12, cy_s + 10
  local short_name = (poi.name or "?"):gsub("_Small$",""):gsub("_Large$","")
  imgui.draw_text(tx, ty,    1,1,1,1,    short_name)
  imgui.draw_text(tx, ty+18, cr,cg,cb,   dist_xy .. "m  (\xce\x94z " .. dz_txt .. "m)")
  imgui.draw_text(tx, ty+36, 0.6,0.6,0.7,1, "x=" .. math.floor(poi.x) .. "  y=" .. math.floor(poi.y))
  -- Proximity pulse ring < 30 m
  if dist_xy < 30 then
    local freq    = dist_xy < 10 and 3 or 1.5
    local pulse_a = (math.sin(farever.now() * freq * math.pi) + 1) * 0.5
    imgui.draw_circle(acx, acy, ar+6, cr,cg,cb, pulse_a*0.8, 1.5)
  end
  imgui.dummy(PLUGIN_W, panel_h + 4)
end

-- ── helpers ──────────────────────────────────────────────────────────────────────────────────

-- Format a float for display: integer if whole, else 2 decimal places.
local function lf(v)
  if v == math.floor(v) then return tostring(math.floor(v)) end
  return string.format("%.2f", v)
end

local function rarity_col(r)
  local c = RARITY_COL[r]
  return c and c[1],c[2],c[3] or 0.8,0.8,0.8
end

-- ── detail renderers ─────────────────────────────────────────────────────────────────────

local function lf(v)
  if v == math.floor(v) then return tostring(math.floor(v)) end
  return string.format("%.2f", v)
end

local function render_item_detail(item_id)
  local item = DB.items[item_id]
  if not item then imgui.text("(unknown item)"); return end
  local src = DB.sources[item_id]

  -- Header: name in rarity colour + type / sell price on same line
  imgui.font_scale(1.15)
  local rr,rg,rb = rarity_col(item.r)
  imgui.text_colored(rr,rg,rb,1, item.n)
  imgui.font_scale(1.0)
  imgui.same_line()
  imgui.text_colored(0.5,0.5,0.5,1, "  " .. (item.r or "") .. " \xc2\xb7 " .. (item.t or ""))
  if (item.sell or 0) > 0 then
    imgui.text_colored(0.9,0.8,0.3,1, "  Sell: " .. item.sell .. "g")
  end
  imgui.separator()

  if not src then
    imgui.text_colored(0.5,0.5,0.5,1, "No known source in database.")
    return
  end

  -- ---- NODE LOCATIONS (ore / plant) ----
  if #state.detail_pois > 0 then
    imgui.text_colored(0.3,1.0,0.5,1, "NODE LOCATIONS")
    imgui.text(#state.detail_pois .. " nodes on map")
    imgui.same_line()
    -- Toggle lock: when locked the arrow stays on the chosen node even
    -- as the player moves; when unlocked it always tracks the nearest one.
    if state.nav_poi then
      local lbl = state.nav_locked and "[Locked]" or "[Nav: Nearest]"
      if imgui.button(lbl) then
        state.nav_locked = not state.nav_locked
        if not state.nav_locked then
          sort_pois_by_dist(state.detail_pois)
          state.nav_poi = state.detail_pois[1]
        end
      end
    end
    -- Full drop table for the matching loot table (shown once per unique lt)
    local lt_shown = {}
    if src.lt then
      for _, lt_src in ipairs(src.lt) do
        local lt = DB.loot_tables[lt_src.id]
        if lt and not lt_shown[lt_src.id] then
          lt_shown[lt_src.id] = true
          imgui.text_colored(0.6,0.6,0.7,1, "Drop table (" .. lt_src.id .. "):")
          for _, d in ipairs(lt.dr) do
            local di = DB.items[d.i]
            local dn = di and di.n or d.n or d.i
            -- Colour-code by drop chance: green >=75%, yellow >=20%, red <5%
            local dr,dg,db = 0.9,0.9,0.9
            if     d.c >= 75 then dr,dg,db = 0.3,1.0,0.3
            elseif d.c >= 20 then dr,dg,db = 1.0,0.85,0.2
            elseif d.c <  5  then dr,dg,db = 0.9,0.4,0.4 end
            imgui.text_colored(dr,dg,db,1, string.format("  %-26s %s%%", dn, lf(d.c)))
          end
        end
      end
    end
    imgui.separator()
  end

  -- ---- DROPPED BY (mob sources) ----
  if src.u and #src.u > 0 then
    imgui.text_colored(0.9,0.6,0.2,1, "DROPPED BY  (" .. #src.u .. " mobs)")
    local shown = 0
    for _, u_src in ipairs(src.u) do
      if shown >= 10 then
        imgui.text_colored(0.5,0.5,0.5,1, "  ... and " .. (#src.u - shown) .. " more")
        break
      end
      local dr,dg,db = 0.9,0.9,0.9
      if     u_src.c >= 50 then dr,dg,db = 0.3,1.0,0.3
      elseif u_src.c >= 15 then dr,dg,db = 1.0,0.85,0.2
      else                       dr,dg,db = 0.9,0.5,0.3 end
      imgui.text(string.format("  %-28s", u_src.n))
      imgui.same_line()
      imgui.text_colored(dr,dg,db,1, string.format("%-6s", lf(u_src.c) .. "%"))
      imgui.same_line()
      imgui.text_colored(0.5,0.5,0.6,1,
        "lv" .. u_src.lv .. "  " .. (u_src.zname ~= "" and u_src.zname or u_src.zn))
      shown = shown + 1
    end
    imgui.separator()
  end

  -- ---- CRAFTED VIA ----
  if src.craft then
    local c = src.craft
    imgui.text_colored(0.6,0.8,1.0,1, "CRAFTED  (" .. c.j .. "  lv " .. c.lv .. ")")
    for _, inp in ipairs(c.inp) do
      local di = DB.items[inp.i]
      local dn = di and di.n or inp.n or inp.i
      imgui.text("  " .. inp.q .. "x  " .. dn)
    end
    imgui.separator()
  end

  -- Navigation arrow panel -- auto-tracks nearest node unless locked
  if state.nav_poi then
    if not state.nav_locked then
      sort_pois_by_dist(state.detail_pois)
      state.nav_poi = state.detail_pois[1]
    end
    render_nav_panel(state.nav_poi)
  end
end

local function render_unit_detail(unit_id)
  local u = DB.units[unit_id]
  if not u then imgui.text("(unknown unit)"); return end

  -- Header: name in amber + level / type / zone
  imgui.font_scale(1.15)
  imgui.text_colored(1,0.8,0.4,1, u.n)
  imgui.font_scale(1.0)
  imgui.text_colored(0.5,0.5,0.5,1,
    "  lv " .. u.lv .. "  \xc2\xb7 " .. u.tp ..
    "  \xc2\xb7 " .. (u.zname ~= "" and u.zname or u.zn))
  imgui.separator()

  if not u.dr or #u.dr == 0 then
    imgui.text_colored(0.5,0.5,0.5,1, "No drops in database.")
    return
  end

  imgui.text_colored(0.9,0.6,0.2,1, "DROPS  (" .. #u.dr .. " items)")
  for _, d in ipairs(u.dr) do
    local di = DB.items[d.i]
    local dn = di and di.n or d.n or d.i
    local dr,dg,db = 0.9,0.9,0.9
    if     d.c >= 50 then dr,dg,db = 0.3,1.0,0.3
    elseif d.c >= 15 then dr,dg,db = 1.0,0.85,0.2
    elseif d.c <  5  then dr,dg,db = 0.9,0.5,0.3 end
    -- [->] jumps the search field to this item and selects it
    if imgui.button("[->]##drop_" .. d.i) then
      state.search = dn
      farever.store.set("if_search", dn)
      do_search(dn)
      for _, e in ipairs(state.results) do
        if e.id == d.i then select_entry("item", d.i); break end
      end
    end
    imgui.same_line()
    imgui.text_colored(dr,dg,db,1, string.format("%-6s", lf(d.c) .. "%"))
    imgui.same_line()
    imgui.text(dn)
  end
end

-- ── lifecycle ────────────────────────────────────────────────────────────────────────────

function on_init()
  -- Build the flat search index once; search is O(n) over ~1 200 entries.
  build_index()
  -- Restore last query and filter so the window reopens where the player left off.
  state.search = farever.store.get("if_search", "")
  state.filter = farever.store.get("if_filter", "all")
  if state.search ~= "" then do_search(state.search) end
end

function on_render()
  imgui.dummy(PLUGIN_W, 0)   -- force window content width (see POI Finder pattern)

  -- search row
  local new_q = imgui.input_text("##ifsearch", state.search)
  if new_q ~= state.search then
    state.search   = new_q
    state.sel_type = nil
    state.sel_id   = nil
    state.nav_poi  = nil
    farever.store.set("if_search", new_q)
    do_search(new_q)
  end
  imgui.same_line()
  if imgui.button("X##ifclear") then
    state.search   = ""
    state.results  = {}
    state.sel_type = nil
    state.sel_id   = nil
    state.nav_poi  = nil
    farever.store.set("if_search", "")
  end

  -- filter tabs: All / Items / Mobs
  local filters = {{"all","All"},{"item","Items"},{"mob","Mobs"}}
  for i, flt in ipairs(filters) do
    if i > 1 then imgui.same_line() end
    if state.filter == flt[1] then
      imgui.text_colored(0.3,0.8,1,1, "[" .. flt[2] .. "]")
    else
      if imgui.button(flt[2] .. "##iff" .. flt[1]) then
        state.filter = flt[1]
        farever.store.set("if_filter", flt[1])
        do_search(state.search)
      end
    end
  end
  imgui.separator()

  -- results list (prefix matches first, max 25 entries)
  if #state.results > 0 then
    for _, e in ipairs(state.results) do
      local is_sel = (state.sel_type == e.tp and state.sel_id == e.id)
      local prefix = e.tp == "unit" and "[MOB] " or ""
      if is_sel then
        imgui.text_colored(0.3,1,0.6,1, "> " .. prefix .. e.nm)
      else
        if imgui.button(prefix .. e.nm .. "##ifr_" .. e.tp .. e.id) then
          select_entry(e.tp, e.id)
        end
      end
    end
    imgui.separator()
  elseif state.search ~= "" then
    imgui.text_colored(0.5,0.5,0.5,1, "No results for: " .. state.search)
    imgui.separator()
  end

  -- detail panel
  if     state.sel_type == "item" then render_item_detail(state.sel_id)
  elseif state.sel_type == "unit" then render_unit_detail(state.sel_id)
  elseif state.search == "" then
    imgui.text_colored(0.4,0.4,0.4,1, "Type an item or mob name to search.")
    imgui.text_colored(0.4,0.4,0.4,1, "Data: FareverDB \xc2\xb7 Nodes: farever.pois()")
  end
end

-- ── events ───────────────────────────────────────────────────────────────────────────────────

function on_event(name, data)
  if name == "hero_locked" then
    -- Zone transition: clear nav so stale coordinates don't mislead the player.
    state.nav_locked  = false
    state.nav_poi     = nil
    state.detail_pois = {}
    state.pois_cache  = nil
  end
end
